'{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "data": {
    "name": "dataset" // Power BI Data
  },
  "facet": {
    // Y-axis categories
    "row": {
      "field": "Category",
      "type": "nominal",
      "sort": {
        "field": "Sales Amount",
        "order": "descending"
      },

      // Might move to config?
      "header": {
        "labelAngle": 0,
        "title": "",
        "labelAlign": "left",
        "labelPadding": 5
      }
    }
  },
  "spec": {
    "layer": [
      {
        // Bars to show the actual
        "mark": {"type": "bar", "color": "#d4dae0", "size": 10, "opacity": 1},
        "encoding": {
          "x": {"field": "Sales Amount", "type": "quantitative"}
        }
      },
      {
        // Ticks to show the target
        "mark": {"type": "tick", "color": "black", "size": 25},
        "encoding": {
          "x": {"field": "Sales Amount (PY)", "type": "quantitative"}
        }
      },
      {
        // Circles to indicate action dots
        "mark": {"type": "circle"},
        "encoding": {
          "x": {"value": -10},
          "color": {
            "condition": [
              {
                // Very bad
                "test": "datum[''Sales Amount''] < 0.50 * datum[''Sales Amount (PY)'']",
                "value": "#f08c00"
              },
              {
                // Bad
                "test": "datum[''Sales Amount''] < 0.75 * datum[''Sales Amount (PY)'']",
                "value": "#ffd43b"
              },
              {
                // Very good
                "test": "datum[''Sales Amount''] > 1.50 * datum[''Sales Amount (PY)'']",
                "value": "#0074ba"
              },
              {
                // Good
                "test": "datum[''Sales Amount''] > 1.25 * datum[''Sales Amount (PY)'']",
                "value": "#4dabf7"
              }
            ],
            "value": null  // No dot if within 96%-105%
          },
          "size": {
            "condition": [
              {
                // Very bad
                "test": "datum[''Sales Amount''] < 0.50 * datum[''Sales Amount (PY)'']",
                "value": 125
              },
              {
                // Bad
                "test": "datum[''Sales Amount''] < 0.75 * datum[''Sales Amount (PY)'']",
                "value": 75
              },
              {
                // Very good
                "test": "datum[''Sales Amount''] > 1.50 * datum[''Sales Amount (PY)'']",
                "value": 125
              },
              {
                // Good
                "test": "datum[''Sales Amount''] > 1.25 * datum[''Sales Amount (PY)'']",
                "value": 75
              }
            ],
            "value": 0  // No dot if within 96%-105%
          }
        }
      },
      {
        // Actuals label (between dot and bar)
        "mark": {"type": "text", "align": "right", "dx": -5},
        "encoding": {
          "x": {"value": -15},
          "text": {"field": "Sales Amount", "type": "quantitative", "format": ",.3s"},
          "color": {
            "condition": [
              {
                // Very bad
                "test": "datum[''Sales Amount''] < 0.50 * datum[''Sales Amount (PY)'']",
                "value": "#f08c00"
              },
              {
                // Bad
                "test": "datum[''Sales Amount''] < 0.75 * datum[''Sales Amount (PY)'']",
                "value": "#ccb35d"
              },
              {
                // Very good
                "test": "datum[''Sales Amount''] > 1.50 * datum[''Sales Amount (PY)'']",
                "value": "#0074ba"
              },
              {
                // Good
                "test": "datum[''Sales Amount''] > 1.25 * datum[''Sales Amount (PY)'']",
                "value": "#4dabf7"
              }
            ],
            "value": "#5d5d5d"  // No dot if within 96%-105%
          }
        }
      },
      {
        // Target label (on top of tick)
        "mark": {"type": "text", "align": "center", "dy": -20},
        "encoding": {
          "x": {"field": "Sales Amount (PY)", "type": "quantitative"},
          "text": {"field": "Sales Amount (PY)", "type": "quantitative", "format": ",.3s"},
          "color": {"value": "#5d5d5d"},
          "size": {"value": 9}
        }
      }
    ]
  }
}'

'{
    "autosize": {
      "type": "fit",
      "contains": "padding"
    },
    "view": {"stroke": "transparent"},
    "font": "Segoe UI",
    "arc": {},
    "area": {
      "line": true,
      "opacity": 0.6
    },
    "bar": {},
    "line": {
      "strokeWidth": 2,
      "strokeCap": "round",
      "strokeJoin": "round"
    },
    "path": {},
    "point": {
      "filled": true,
      "size": 75
    },
    "rect": {},
    "shape": {},
    "symbol": {},
    "text": {
      "font": "Segoe UI Light",
      "fontSize": 12,
      "fill": "#AAAAAA"
    },
    "axis": {
      "ticks": false,
      "grid": false,
      "domain": false,
      "labelColor": "#AAAAAA",
      "labelFontSize": 12,
      "titleFont": "Segoe UI Light",
      "titleColor": "#AAAAAA",
      "titleFontSize": 10
    },
    "axisQuantitative": {
      "tickCount": 5,
      "grid": true,
      "gridColor": "#CCCCCC",
      "gridDash": [1, 3],
      "labelFlush": false
    },
    "axisX": {"labelPadding": 2.5},
    "header": {
      "labelFont": "Segoe UI Semibold",
      "labelFontSize": 12,
      "labelColor": "#5D5D5D"
    },
    "tick": {"thickness": 1.5},
    "facet": {
      "spacing": 7.5  // Spacing between categories
    }
  }'
